select * from orders
where user_id = #{userId}
  and status = 1
  and pay_status = 0
  and order_time >= #{expireTime}
    limit 1

select * from orders
where user_id = #{userId}

    and status = #{status}

order by order_time desc

select * from orders


        and number like concat('%',#{number},'%')


        and phone like concat('%',#{phone},'%')


        and status = #{status}


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


order by order_time desc
